 {"id":"brenner_bot-it7r","title":"Task: Animation & Utility Component Tests","description":"# Goal
Add unit tests for animation wrappers and utility components.

# Components to Test

## 1. animated-element.tsx (6.1KB)
Test animation wrapper:
- Renders children correctly
- Applies animation classes
- Respects reduced-motion preference
- Handles intersection observer triggers
- Cleanup on unmount

## 2. animated-counter.tsx (2.0KB)
Test counter animation:
- Counts from 0 to target
- Animation duration
- Number formatting
- Immediate display on reduced-motion
- Re-animation on value change

## 3. jargon-text.tsx (7.8KB)
Test jargon inline rendering:
- Identifies jargon terms in text
- Renders tooltip triggers
- Tooltip content display
- Multiple terms in same text
- Nested jargon handling
- Performance with large text

# Test Pattern (Animation-Safe)
```typescript
// animated-element.test.tsx
import { render, screen } from '@testing-library/react';
import { AnimatedElement } from './animated-element';

describe('AnimatedElement', () => {
  it('renders children without animation in test env', () => {
    // Note: framer-motion is mocked in test-setup.tsx
    render(
      <AnimatedElement animation="fade-in">
        <div data-testid="child">Content</div>
      </AnimatedElement>
    );

    expect(screen.getByTestId('child')).toBeInTheDocument();
    expect(screen.getByTestId('child')).toBeVisible();
  });

  it('applies data attributes for animation type', () => {
    render(
      <AnimatedElement animation="slide-up" data-testid="wrapper">
        <div>Content</div>
      </AnimatedElement>
    );

    expect(screen.getByTestId('wrapper'))
      .toHaveAttribute('data-animation', 'slide-up');
  });
});

// animated-counter.test.tsx
import { render, screen, waitFor } from '@testing-library/react';
import { AnimatedCounter } from './animated-counter';

describe('AnimatedCounter', () => {
  it('displays final value (animation mocked)', () => {
    render(<AnimatedCounter value={1234} />);

    // With mocked animations, should show final value
    expect(screen.getByText('1,234')).toBeInTheDocument();
  });

  it('formats numbers with locale', () => {
    render(<AnimatedCounter value={1000000} />);
    expect(screen.getByText('1,000,000')).toBeInTheDocument();
  });
});

// jargon-text.test.tsx
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { JargonText } from './jargon-text';

describe('JargonText', () => {
  it('highlights known jargon terms', () => {
    render(<JargonText>The third alternative is key.</JargonText>);

    const term = screen.getByText('third alternative');
    expect(term).toHaveClass('jargon-term');
  });

  it('shows definition tooltip on hover', async () => {
    const user = userEvent.setup();
    render(<JargonText>The third alternative is key.</JargonText>);

    await user.hover(screen.getByText('third alternative'));

    await waitFor(() => {
      expect(screen.getByRole('tooltip')).toHaveTextContent(/§103/);
    });
  });
});
```

